1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const COMPONENT_BASE_PREMIUM = 25;
4	const COMPONENT_INSURANCE_VALUE = 250;
5	const BLOCK_SIZE = 3;
6	const BLOCK_BASE_PREMIUM = 60;
7	const CURSE_SURCHARGE_RATE = 0.5;
8	const HIGH_ENCHANTMENT_THRESHOLD = 5;
9	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
10	const LOYALTY_DISCOUNT_RATE = 0.2;
11	const LOYALTY_YEARS_THRESHOLD = 2;
12	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
13	const DEDUCTIBLE = 100;
14	const CAP_MULTIPLIER = 2;
15	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
16	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
17	const DRAGON_MATERIAL = "dragon";
18	
19	const MAIN_ITEM_INFO: Record<string, { basePremium: number; insuranceValue: number }> = {
20	  sword: { basePremium: 100, insuranceValue: 1000 },
21	  amulet: { basePremium: 60, insuranceValue: 600 },
22	  staff: { basePremium: 80, insuranceValue: 800 },
23	  potion: { basePremium: 40, insuranceValue: 400 },
24	};
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	
28	type Item = {
29	  type: string;
30	  material?: string;
31	  enchantment?: number;
32	  cursed?: boolean;
33	};
34	
35	type QuoteStep = { op: "quote"; items: Array<Item> };
36	
37	type Damage = { itemType: string; amount: number };
38	type Incident = { cause: string; damages: Array<Damage> };
39	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
40	
41	type Step = QuoteStep | ClaimStep;
42	
43	type Customer = { yearsWithMHPCO: number };
44	
45	type Scenario = {
46	  customer: Customer;
47	  steps: Array<Step>;
48	};
49	
50	type QuoteResult = { premium: number };
51	type ClaimResult = { payout: number; remainingCap: number };
52	type StepResult = QuoteResult | ClaimResult;
53	
54	type Policy = {
55	  items: Array<Item>;
56	  insuranceSum: number;
57	  remainingCap: number;
58	};
59	
60	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
61	
62	const isKnownItemType = (type: string): boolean =>
63	  type in MAIN_ITEM_INFO || COMPONENT_TYPES.has(type);
64	
65	const validateItems = (items: Array<Item>): void => {
66	  for (const item of items) {
67	    if (!isKnownItemType(item.type)) {
68	      throw new Error(`Unknown item type: ${item.type}`);
69	    }
70	  }
71	};
72	
73	const componentsBasePremium = (components: Array<Item>): number => {
74	  const byType = new Map<string, number>();
75	  for (const c of components) {
76	    byType.set(c.type, (byType.get(c.type) ?? 0) + 1);
77	  }
78	  let total = 0;
79	  for (const count of byType.values()) {
80	    if (count === BLOCK_SIZE) {
81	      total += BLOCK_BASE_PREMIUM;
82	    } else {
83	      total += count * COMPONENT_BASE_PREMIUM;
84	    }
85	  }
86	  return total;
87	};
88	
89	const policyBasePremium = (items: Array<Item>): number => {
90	  const mains = items.filter((i) => !isComponent(i));
91	  const components = items.filter(isComponent);
92	  const mainsTotal = mains.reduce((sum, item) => sum + MAIN_ITEM_INFO[item.type].basePremium, 0);
93	  return mainsTotal + componentsBasePremium(components);
94	};
95	
96	const itemSurcharges = (items: Array<Item>): number => {
97	  let total = 0;
98	  for (const item of items) {
99	    if (isComponent(item)) continue;
100	    const base = MAIN_ITEM_INFO[item.type].basePremium;
101	    if (item.cursed) total += base * CURSE_SURCHARGE_RATE;
102	    const enchantment = item.enchantment ?? 0;
103	    if (enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
104	      total += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
105	    }
106	  }
107	  return total;
108	};
109	
110	const insuranceValueOf = (item: Item): number =>
111	  isComponent(item) ? COMPONENT_INSURANCE_VALUE : MAIN_ITEM_INFO[item.type].insuranceValue;
112	
113	const insuranceSum = (items: Array<Item>): number =>
114	  items.reduce((sum, item) => sum + insuranceValueOf(item), 0);
115	
116	const quoteStep = (
117	  step: QuoteStep,
118	  customer: Customer,
119	  isFollowUpContract: boolean,
120	): { result: QuoteResult; policy: Policy } => {
121	  validateItems(step.items);
122	  const policyBase = policyBasePremium(step.items);
123	  const surcharges = itemSurcharges(step.items);
124	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
125	  const loyaltyDiscount =
126	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
127	  const followUpDiscount = isFollowUpContract ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
128	  const premium = Math.ceil(
129	    policyBase +
130	      surcharges +
131	      firstInsurance -
132	      loyaltyDiscount -
133	      followUpDiscount +
134	      PROCESSING_FEE,
135	  );
136	  const sum = insuranceSum(step.items);
137	  return {
138	    result: { premium },
139	    policy: { items: step.items, insuranceSum: sum, remainingCap: sum * CAP_MULTIPLIER },
140	  };
141	};
142	
143	const reimbursementFor = (item: Item, damageAmount: number): number => {
144	  const enchantment = item.enchantment ?? 0;
145	  if (enchantment >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) {
146	    return damageAmount * HIGH_ENCHANTMENT_PAYOUT_RATE;
147	  }
148	  if (item.material === DRAGON_MATERIAL) {
149	    return damageAmount;
150	  }
151	  return damageAmount;
152	};
153	
154	const countByType = <T extends { itemType: string } | { type: string }>(
155	  entries: Array<T>,
156	  key: (e: T) => string,
157	): Map<string, number> => {
158	  const counts = new Map<string, number>();
159	  for (const e of entries) {
160	    const k = key(e);
161	    counts.set(k, (counts.get(k) ?? 0) + 1);
162	  }
163	  return counts;
164	};
165	
166	const validateDamagesAgainstPolicy = (damages: Array<Damage>, policy: Policy): void => {
167	  const policyCounts = countByType(policy.items, (i) => i.type);
168	  const damageCounts = countByType(damages, (d) => d.itemType);
169	  for (const [itemType, count] of damageCounts) {
170	    const available = policyCounts.get(itemType) ?? 0;
171	    if (count > available) {
172	      throw new Error(
173	        `Claim damages exceed policy coverage for itemType: ${itemType} (claimed ${count}, covered ${available})`,
174	      );
175	    }
176	  }
177	};
178	
179	const validateDamages = (damages: Array<Damage>): void => {
180	  for (const damage of damages) {
181	    if (damage.amount < 0) {
182	      throw new Error(`Damage amount must be non-negative, got ${damage.amount}`);
183	    }
184	  }
185	};
186	
187	const claimStep = (step: ClaimStep, policy: Policy): ClaimResult => {
188	  validateDamages(step.incident.damages);
189	  validateDamagesAgainstPolicy(step.incident.damages, policy);
190	  let payout = 0;
191	  for (const damage of step.incident.damages) {
192	    const item = policy.items.find((i) => i.type === damage.itemType);
193	    if (!item) throw new Error(`Claim references item not in policy: ${damage.itemType}`);
194	    const reimbursement = reimbursementFor(item, damage.amount);
195	    const afterDeductible = Math.max(0, reimbursement - DEDUCTIBLE);
196	    payout += afterDeductible;
197	  }
198	  payout = Math.min(payout, policy.remainingCap);
199	  policy.remainingCap -= payout;
200	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
201	};
202	
203	export const runScenario = (scenario: Scenario): { results: Array<StepResult> } => {
204	  let quoteCount = 0;
205	  const policies: Array<Policy> = [];
206	  const results: Array<StepResult> = scenario.steps.map((step, index) => {
207	    if (step.op === "quote") {
208	      const { result, policy } = quoteStep(step, scenario.customer, quoteCount > 0);
209	      quoteCount++;
210	      policies[index] = policy;
211	      return result;
212	    }
213	    const policy = policies[step.policy];
214	    return claimStep(step, policy);
215	  });
216	  return { results };
217	};
