3	const readStdin = async (): Promise<string> => {
4	  const chunks: Array<Buffer> = [];
5	  for await (const chunk of process.stdin) {
6	    chunks.push(chunk as Buffer);
7	  }
8	  return Buffer.concat(chunks).toString("utf-8");
9	};
10	
11	const main = async (): Promise<void> => {
12	  try {
13	    const input = await readStdin();
14	    const scenario = JSON.parse(input);
15	    const output = runScenario(scenario);
16	    process.stdout.write(JSON.stringify(output));
17	  } catch (err) {
18	    const message = err instanceof Error ? err.message : String(err);
19	    process.stderr.write(`${message}\n`);
20	    process.exit(1);
21	  }
22	};
23	
24	void main();
