const reimbursementFor = (item: Item, damageAmount: number): number => {
  const enchantment = item.enchantment ?? 0;
  if (enchantment >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD) {
    return damageAmount * HIGH_ENCHANTMENT_PAYOUT_RATE;
