88	const itemSurcharges = (items: Array<Item>): number => {
89	  let total = 0;
90	  for (const item of items) {
91	    if (isComponent(item)) continue;
92	    const base = MAIN_ITEM_INFO[item.type].basePremium;
93	    if (item.cursed) total += base * CURSE_SURCHARGE_RATE;
94	    const enchantment = item.enchantment ?? 0;
95	    if (enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
96	      total += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
97	    }
98	  }
99	  return total;
100	};
