102	const insuranceValueOf = (item: Item): number =>
103	  isComponent(item) ? COMPONENT_INSURANCE_VALUE : MAIN_ITEM_INFO[item.type].insuranceValue;
104	
105	const insuranceSum = (items: Array<Item>): number =>
106	  items.reduce((sum, item) => sum + insuranceValueOf(item), 0);
107	
108	const quoteStep = (
109	  step: QuoteStep,
110	  customer: Customer,
111	  isFollowUpContract: boolean,
112	): { result: QuoteResult; policy: Policy } => {
113	  validateItems(step.items);
114	  const policyBase = policyBasePremium(step.items);
115	  const surcharges = itemSurcharges(step.items);
116	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
117	  const loyaltyDiscount =
