143	const countByType = <T extends { itemType: string } | { type: string }>(
144	  entries: Array<T>,
145	  key: (e: T) => string,
146	): Map<string, number> => {
147	  const counts = new Map<string, number>();
148	  for (const e of entries) {
149	    const k = key(e);
150	    counts.set(k, (counts.get(k) ?? 0) + 1);
151	  }
152	  return counts;
153	};
154	
155	const validateDamagesAgainstPolicy = (damages: Array<Damage>, policy: Policy): void => {
156	  const policyCounts = countByType(policy.items, (i) => i.type);
157	  const damageCounts = countByType(damages, (d) => d.itemType);
158	  for (const [itemType, count] of damageCounts) {
159	    const available = policyCounts.get(itemType) ?? 0;
160	    if (count > available) {
161	      throw new Error(
162	        `Claim damages exceed policy coverage for itemType: ${itemType} (claimed ${count}, covered ${available})`,
163	      );
164	    }
165	  }
166	};
167	
168	const validateDamages = (damages: Array<Damage>): void => {
169	  for (const damage of damages) {
170	    if (damage.amount < 0) {
171	      throw new Error(`Damage amount must be non-negative, got ${damage.amount}`);
172	    }
173	  }
174	};
175	
176	const claimStep = (step: ClaimStep, policy: Policy): ClaimResult => {
177	  validateDamages(step.incident.damages);
178	  validateDamagesAgainstPolicy(step.incident.damages, policy);
179	  let payout = 0;
180	  for (const damage of step.incident.damages) {
181	    const item = policy.items.find((i) => i.type === damage.itemType);
182	    if (!item) throw new Error(`Claim references item not in policy: ${damage.itemType}`);
183	    const reimbursement = reimbursementFor(item, damage.amount);
184	    const afterDeductible = Math.max(0, reimbursement - DEDUCTIBLE);
185	    payout += afterDeductible;
186	  }
187	  payout = Math.min(payout, policy.remainingCap);
188	  policy.remainingCap -= payout;
189	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
190	};
