192	export const runScenario = (scenario: Scenario): { results: Array<StepResult> } => {
193	  let quoteCount = 0;
194	  const policies: Array<Policy> = [];
195	  const results: Array<StepResult> = scenario.steps.map((step, index) => {
196	    if (step.op === "quote") {
197	      const { result, policy } = quoteStep(step, scenario.customer, quoteCount > 0);
198	      quoteCount++;
199	      policies[index] = policy;
200	      return result;
201	    }
202	    const policy = policies[step.policy];
203	    return claimStep(step, policy);
204	  });
205	  return { results };
206	};
